static const int gsh_ssi_table_size = 543;

/* Binary search for an embedded .ssi file by path.
   Returns pointer to data and sets *size, or NULL if not found. */
const char* gsh_find_embedded_ssi(const char *path, unsigned int *size) {
    int lo = 0, hi = gsh_ssi_table_size - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        int cmp = strcmp(path, gsh_ssi_table[mid].path);
        if (cmp == 0) {
            if (size) *size = gsh_ssi_table[mid].size;
            return gsh_ssi_table[mid].data;
        } else if (cmp < 0) {
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return NULL;
}

#include <stdio.h>
#include <sys/stat.h>
#include <errno.h>
#include <libgen.h>

/* Ensure all parent directories exist for a file path */
static int mkdirs(const char *filepath) {
    char tmp[4096];
    snprintf(tmp, sizeof(tmp), "%s", filepath);
    /* Find last / to get directory part */
    char *last_slash = strrchr(tmp, '/');
    if (!last_slash) return 0;
    *last_slash = '\0';
    /* Create each directory component */
    for (char *p = tmp + 1; *p; p++) {
        if (*p == '/') {
            *p = '\0';
            mkdir(tmp, 0755);
            *p = '/';
        }
    }
    mkdir(tmp, 0755);
    return 0;
}

/* Extract all embedded .ssi files to a directory.
   Returns number of files extracted, or -1 on error. */
int gsh_extract_embedded_ssi(const char *base_dir) {
    int count = 0;
    char path[4096];
    for (int i = 0; i < gsh_ssi_table_size; i++) {
        snprintf(path, sizeof(path), "%s/%s", base_dir, gsh_ssi_table[i].path);
        mkdirs(path);
        FILE *f = fopen(path, "w");
        if (!f) return -1;
        fwrite(gsh_ssi_table[i].data, 1, gsh_ssi_table[i].size, f);
        fclose(f);
        count++;
    }
    return count;
}

/* Check if embedded .ssi data is available (table is non-empty) */
int gsh_has_embedded_ssi(void) {
    return gsh_ssi_table_size > 0;
}
